const now = new Date();
const yesterday = new Date(now);
yesterday.setUTCDate(now.getUTCDate() - 1);
const year = yesterday.getUTCFullYear();
const month = String(yesterday.getUTCMonth() + 1).padStart(2, '0');
const day = String(yesterday.getUTCDate()).padStart(2, '0');
const postedAfter = `${year}-${month}-${day}T00:00:00Z`;
const postedBefore = `${year}-${month}-${day}T23:59:59Z`;
const dateLabel = `${year}-${month}-${day}`;
return [{ json: { postedAfter, postedBefore, dateLabel } }];

const input = $input.all();
const data = input[0].json;
const dateLabel = $('Build Date Range').first().json.dateLabel;

const edges = data?.data?.posts?.edges || [];
const products = edges.map(edge => {
  const p = edge.node;
  return {
    id: p.id, name: p.name, slug: p.slug,
    tagline: p.tagline, description: p.description,
    website: p.website,
    url: p.url || `https://www.producthunt.com/posts/${p.slug}`,
    votesCount: p.votesCount || 0,
    commentsCount: p.commentsCount || 0,
    reviewsRating: p.reviewsRating || 0,
    createdAt: p.createdAt, featuredAt: p.featuredAt,
    thumbnail: p.thumbnail?.url || '',
    maker: p.user ? { name: p.user.name, headline: p.user.headline, username: p.user.username, twitter: p.user.twitterUsername } : null,
    makers: (p.makers || []).map(m => ({ name: m.name, headline: m.headline, username: m.username, twitter: m.twitterUsername })),
    topics: (p.topics?.edges || []).map(t => t.node.name)
  };
});

products.sort((a, b) => b.votesCount - a.votesCount);
const top15 = products.slice(0, 15);

const aiInput = top15.map((p, i) => {
  const makers = p.makers.map(m => m.name).join(', ') || (p.maker?.name || 'Unknown');
  return `#${i + 1} ${p.name} | ${p.votesCount}票 ${p.commentsCount}评 | ${p.tagline} | ${p.description || ''} | Topics: ${p.topics.join(', ') || 'N/A'} | Makers: ${makers} | ${p.url}`;
}).join('\n');

const rankingList = top15.map((p, i) => {
  const medal = i === 0 ? '🥇' : i === 1 ? '🥈' : i === 2 ? '🥉' : `\`${String(i + 1).padStart(2)}\``;
  return `${medal} **[${p.name}](${p.url})** · 🔺${p.votesCount}`;
}).join('\n');

return [{ json: { dateLabel, totalCount: products.length, top15, allProducts: products, aiInput, rankingList } }];

const fs = require('fs');
const path = require('path');
const { dateLabel, allProducts, totalCount, top15, aiInput, rankingList } = $input.first().json;
const dir = '/data/ph-monitor';
if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
const filePath = path.join(dir, `ph-raw-${dateLabel}.json`);
fs.writeFileSync(filePath, JSON.stringify({ date: dateLabel, totalCount, products: allProducts }, null, 2), 'utf-8');
return [{ json: { dateLabel, totalCount, top15, aiInput, rankingList, savedTo: filePath } }];

const fs = require('fs');
const path = require('path');
const deepseekResponse = $input.first().json;
const dateLabel = $('Build Date Range').first().json.dateLabel;
const analysis = deepseekResponse?.choices?.[0]?.message?.content || 'Analysis unavailable.';
const dir = '/data/ph-monitor';
if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
const filePath = path.join(dir, `ph-analysis-${dateLabel}.md`);
fs.writeFileSync(filePath, analysis, 'utf-8');
return [{ json: { ...deepseekResponse, savedAnalysisTo: filePath } }];

const deepseekResponse = $input.first().json;
const analysis = deepseekResponse?.choices?.[0]?.message?.content || 'Analysis unavailable.';

const MAX_LEN = 1900;
const messages = [];
const paragraphs = analysis.split('\n');
let currentChunk = '';
for (const para of paragraphs) {
  if ((currentChunk + '\n' + para).length > MAX_LEN) {
    if (currentChunk.trim()) messages.push(currentChunk.trim());
    if (para.length > MAX_LEN) {
      let remaining = para;
      while (remaining.length > MAX_LEN) {
        messages.push(remaining.substring(0, MAX_LEN));
        remaining = remaining.substring(MAX_LEN);
      }
      currentChunk = remaining;
    } else {
      currentChunk = para;
    }
  } else {
    currentChunk += (currentChunk ? '\n' : '') + para;
  }
}
if (currentChunk.trim()) messages.push(currentChunk.trim());
messages.push(`-# 🤖 PH Daily Monitor · DeepSeek`);
return messages.map(content => ({ json: { content } }));
